// NormalizeRows: Map Source CSV Research Market CSV → Lead Contacts schema
// Input: raw rows from Source CSV_Import tab (contact pastes new CSV here weekly)
// Output: normalized contact records with signal_tier scoring
//
// DATA SOURCE: Source CSV 'Research Market' report
// Columns: Type, Research Market Name, Property Type, Search Type,
//          Company Name, Company Industry, Company City, Company State,
//          Company Website, Total Views-30days, Search Impression Views - 30days, Detail Page
//
// SIGNAL LOGIC:
//   Detail Page views = company clicked INTO specific listings (strongest intent)
//   Tier 1 (hot):    >= 10 detail page views
//   Tier 2 (active): 3-9 detail page views
//   Tier 3 (cold):   < 3 detail page views (impressions only)

return items
  .filter(item => item.json['Company Name'] && String(item.json['Company Name']).trim())
  .map(item => {
    const r = item.json;

    // Parse view counts — handle numbers formatted with commas
    const detailViews = parseInt(String(r['Detail Page'] || r['Detail Page Views'] || '0').replace(/,/g, '')) || 0;
    const totalViews  = parseInt(String(r['Total Views-30days'] || r['Total Views'] || '0').replace(/,/g, '')) || 0;

    // Score by detail page views (clicked into listing = real intent)
    let signal_tier, why_now;
    if (detailViews >= 10) {
      signal_tier = 1;
      why_now = `High intent — read ${detailViews} listings in past 30 days`;
    } else if (detailViews >= 3) {
      signal_tier = 2;
      why_now = `Active search — viewed ${detailViews} detail pages`;
    } else {
      signal_tier = 3;
      why_now = `Low engagement — ${totalViews} impressions, ${detailViews} detail views`;
    }

    // Stable contact_id: company + search type (Sale vs Lease = different record)
    const contact_id = `${r['Company Name']}_${r['Type'] || 'unknown'}`
      .toLowerCase()
      .replace(/\s+/g, '_')
      .replace(/[^a-z0-9_]/g, '')
      .substring(0, 64);

    const searchType = String(r['Type'] || '').trim();

    return {
      json: {
        contact_id,
        company:              String(r['Company Name'] || '').trim(),
        industry:             String(r['Company Industry'] || '').trim(),
        city:                 String(r['Company City'] || '').trim(),
        state:                String(r['Company State'] || '').trim(),
        website:              String(r['Company Website'] || '').trim(),
        search_type:          searchType,
        asset_interest:       String(r['Property Type'] || '').trim(),
        market:               String(r['Research Market Name'] || 'Los Angeles').trim(),
        detail_views:         detailViews,
        total_views:          totalViews,
        signal_tier,
        why_now,
        role:                 searchType.toLowerCase() === 'sale' ? 'buyer_prospect' : 'tenant_prospect',
        name:                 '',
        email:                '',
        phone:                '',
        status:               'never_contacted',
        last_contact_date:    '',
        sequence_step:        0,
        next_follow_up_date:  '',
        source:               'source_csv_research_report',
        source_date:          new Date().toISOString().split('T')[0],
        created_at:           new Date().toISOString()
      }
    };
  });

const allRows = $('Upsert Contacts').all();

const tier1   = allRows.filter(r => Number(r.json.signal_tier) === 1).length;
const tier2   = allRows.filter(r => Number(r.json.signal_tier) === 2).length;
const tier3   = allRows.filter(r => Number(r.json.signal_tier) === 3).length;
const buyers  = allRows.filter(r => r.json.role === 'buyer_prospect').length;
const tenants = allRows.filter(r => r.json.role === 'tenant_prospect').length;

const topTier1 = allRows
  .filter(r => Number(r.json.signal_tier) === 1)
  .sort((a, b) => Number(b.json.detail_views) - Number(a.json.detail_views))
  .slice(0, 5)
  .map(r => `${r.json.company} (${r.json.detail_views} detail views — ${r.json.role})`);

const summary = {
  total_processed: allRows.length,
  tier_1_hot:      tier1,
  tier_2_active:   tier2,
  tier_3_cold:     tier3,
  buyers,
  tenants,
  top_5_tier1:     topTier1,
  source_date:     allRows[0]?.json?.source_date || '',
  completed_at:    new Date().toISOString()
};

console.log('Lead_Weekly_Refresh complete:', JSON.stringify(summary, null, 2));
return [{ json: { success: true, summary } }];
